122→const makeInkSceneFunc = (points, widths, baseWidth, color) => (ctx, shape) => {
123→    if(points.length < 4){
124→        return;
125→    }
126→
127→    const numPts = points.length / 2;
128→    const xs = [];
129→    const ys = [];
130→    for(let i = 0; i < numPts; i++){
131→        xs.push(points[i * 2]);
132→        ys.push(points[i * 2 + 1]);
133→    }
134→
135→    ctx.strokeStyle = color;
136→    ctx.lineCap = "round";
137→    ctx.lineJoin = "round";
138→
139→    if(numPts === 2){
140→        ctx.lineWidth = baseWidth * (widths[0] ?? 1);
141→        ctx.beginPath();
142→        ctx.moveTo(xs[0], ys[0]);
143→        ctx.lineTo(xs[1], ys[1]);
144→        ctx.stroke();
145→        return;
146→    }
147→
148→    for(let i = 0; i < numPts - 1; i++){
149→        const w = widths[i] ?? widths[widths.length - 1] ?? 1;
150→        ctx.lineWidth = baseWidth * w;
151→        ctx.beginPath();
152→
153→        if(i === 0){
154→            ctx.moveTo(xs[0], ys[0]);
155→        } else {
156→            ctx.moveTo((xs[i - 1] + xs[i]) / 2, (ys[i - 1] + ys[i]) / 2);
157→        }
158→
159→        if(i === numPts - 2){
160→            ctx.quadraticCurveTo(xs[i], ys[i], xs[i + 1], ys[i + 1]);
161→        } else {
162→            ctx.quadraticCurveTo(xs[i], ys[i], (xs[i] + xs[i + 1]) / 2, (ys[i] + ys[i + 1]) / 2);
163→        }
164→
165→        ctx.stroke();
166→    }
167→
168→    const lastW = widths[widths.length - 1] ?? 1;
169→    const endR = (baseWidth * lastW) / 2;
170→    ctx.fillStyle = color;
171→    ctx.beginPath();
172→    ctx.arc(xs[numPts - 1], ys[numPts - 1], endR, 0, Math.PI * 2);
173→    ctx.fill();
174→};
