214→const distancePointToSegment = (px, py, x1, y1, x2, y2) => {
215→    const dx = x2 - x1;
216→    const dy = y2 - y1;
217→    if(dx === 0 && dy === 0){
218→        return Math.hypot(px - x1, py - y1);
219→    }
220→
221→    const t = clamp(((px - x1) * dx + (py - y1) * dy) / (dx * dx + dy * dy), 0, 1);
222→    const cx = x1 + t * dx;
223→    const cy = y1 + t * dy;
224→    return Math.hypot(px - cx, py - cy);
225→};
