408→const NoteNode = ({
409→    item,
410→    stageWidth,
411→    stageHeight,
412→    canEdit,
413→    onSelect,
414→    onDragEnd,
415→    isSelected,
416→    isDraft
417→}) => {
418→    const payload = item?.payload || {};
419→    const wallSizeScale = getWallSizeScale(stageWidth);
420→    const width = clamp((Number(payload?.width) || 0.26) * stageWidth, 110 * wallSizeScale, stageWidth * 0.9);
421→    const height = clamp((Number(payload?.height) || 0.2) * stageHeight, 60 * wallSizeScale, stageHeight * 0.8);
422→    const x = clamp((Number(payload?.x) || 0.45) * stageWidth, 0, Math.max(0, stageWidth - width));
423→    const y = clamp((Number(payload?.y) || 0.45) * stageHeight, 0, Math.max(0, stageHeight - height));
424→    const fontStyle = NOTE_STYLE_OPTIONS.includes(payload?.fontStyle) ? payload.fontStyle : "normal";
425→    const bgColor = payload?.bgColor || "#fff4a8";
426→    const curlSize = Math.min(width, height) * 0.14;
427→    const pinSize = Math.max(5, Math.min(width, height) * 0.04);
428→
429→    const borderStroke = isDraft ? "#a21caf" : isSelected ? "#a21caf" : "rgba(0,0,0,0.1)";
430→    const borderWidth = isDraft ? 2 : isSelected ? 2 : 0.5;
431→    const borderDash = isDraft ? [6, 4] : undefined;
432→
433→    return (
434→        <Group
435→            x={x}
436→            y={y}
437→            draggable={canEdit}
438→            onDragEnd={onDragEnd}
439→            onClick={onSelect}
440→            onTap={onSelect}
441→            rotation={Number(payload?.rotation) || 0}
442→        >
443→            {/* Shadow layer beneath the note */}
444→            <Shape
445→                sceneFunc={(ctx, shape) => {
446→                    ctx.beginPath();
447→                    ctx.moveTo(2, 4);
448→                    ctx.lineTo(width + 2, 2);
449→                    ctx.lineTo(width - curlSize + 4, height + 3);
450→                    ctx.lineTo(2, height + 2);
451→                    ctx.closePath();
452→                    ctx.fillStrokeShape(shape);
453→                }}
454→                fill="rgba(0,0,0,0.12)"
455→                listening={false}
456→            />
457→
458→            {/* Main note body */}
459→            <Shape
460→                sceneFunc={(ctx, shape) => {
461→                    ctx.beginPath();
462→                    ctx.moveTo(0, 0);
463→                    ctx.lineTo(width, 0);
464→                    ctx.lineTo(width, height - curlSize);
465→                    ctx.lineTo(width - curlSize, height);
466→                    ctx.lineTo(0, height);
467→                    ctx.closePath();
468→                    ctx.fillStrokeShape(shape);
469→                }}
470→                fill={bgColor}
471→                stroke={borderStroke}
472→                strokeWidth={borderWidth}
473→                dash={borderDash}
474→            />
475→
476→            {/* Page curl triangle */}
477→            <Shape
478→                sceneFunc={(ctx, shape) => {
479→                    ctx.beginPath();
480→                    ctx.moveTo(width, height - curlSize);
481→                    ctx.lineTo(width - curlSize, height - curlSize);
482→                    ctx.lineTo(width - curlSize, height);
483→                    ctx.closePath();
484→                    ctx.fillStrokeShape(shape);
485→                }}
486→                fill={darkenColor(bgColor, 0.12)}
487→                listening={false}
488→            />
489→
490→            {/* Curl fold shadow */}
491→            <Shape
492→                sceneFunc={(ctx, shape) => {
493→                    ctx.beginPath();
494→                    ctx.moveTo(width - curlSize, height);
495→                    ctx.lineTo(width, height - curlSize);
496→                    ctx.lineTo(width - curlSize * 0.55, height - curlSize * 0.55);
497→                    ctx.closePath();
498→                    ctx.fillStrokeShape(shape);
499→                }}
500→                fill="rgba(0,0,0,0.06)"
501→                listening={false}
502→            />
503→
504→            {/* Text content */}
505→            <Text
506→                x={12}
507→                y={pinSize * 2 + 10}
508→                width={width - 24}
509→                height={height - pinSize * 2 - curlSize - 16}
510→                text={payload?.text || ""}
511→                fontFamily={payload?.fontFamily || "Arial"}
512→                fontStyle={fontStyle}
513→                fontSize={clamp((Number(payload?.fontSize) || 16) * wallSizeScale, 10 * wallSizeScale, 64 * wallSizeScale)}
514→                fill={payload?.fontColor || "#1f2937"}
515→                wrap="word"
516→                lineHeight={1.3}
517→            />
518→
519→            {/* Left push pin */}
520→            <Circle x={width * 0.18} y={pinSize + 2} radius={pinSize} fill="#e63946" stroke="#b71c2a" strokeWidth={1} listening={false} />
521→            <Line points={[width * 0.18, pinSize * 2 + 2, width * 0.18, pinSize * 2 + 6]} stroke="#999" strokeWidth={1.5} listening={false} />
522→
523→            {/* Right push pin */}
524→            <Circle x={width * 0.82} y={pinSize + 2} radius={pinSize} fill="#e63946" stroke="#b71c2a" strokeWidth={1} listening={false} />
525→            <Line points={[width * 0.82, pinSize * 2 + 2, width * 0.82, pinSize * 2 + 6]} stroke="#999" strokeWidth={1.5} listening={false} />
526→
527→            {/* Pin highlights (glossy effect) */}
528→            <Circle x={width * 0.18 - pinSize * 0.25} y={pinSize * 0.7 + 2} radius={pinSize * 0.3} fill="rgba(255,255,255,0.45)" listening={false} />
529→            <Circle x={width * 0.82 - pinSize * 0.25} y={pinSize * 0.7 + 2} radius={pinSize * 0.3} fill="rgba(255,255,255,0.45)" listening={false} />
530→        </Group>
531→    );
532→};
