642→const formatWeekLabel = (week = null) => {
643→    if(!week?.week_start || !week?.week_end){
644→        return "No active week";
645→    }
646→
647→    const startDate = new Date(week.week_start);
648→    const endDate = new Date(week.week_end);
649→    return `${startDate.toLocaleDateString()} - ${endDate.toLocaleDateString()} (UTC)`;
650→};
651→
652→const formatResetCountdown = (weekEnd, nowMs) => {
653→    if(!weekEnd){
654→        return "No reset scheduled";
655→    }
656→
657→    const endTimeMs = new Date(weekEnd).getTime();
658→    if(Number.isNaN(endTimeMs)){
659→        return "No reset scheduled";
660→    }
661→
662→    const diffMs = endTimeMs - nowMs;
663→    if(diffMs <= 0){
664→        return "Reset imminent";
665→    }
666→
667→    const totalSeconds = Math.floor(diffMs / 1000);
668→    const days = Math.floor(totalSeconds / 86400);
669→    const hours = Math.floor((totalSeconds % 86400) / 3600);
670→    const minutes = Math.floor((totalSeconds % 3600) / 60);
671→
672→    if(days > 0){
673→        return `${days} day${days === 1 ? "" : "s"}, ${hours} hour${hours === 1 ? "" : "s"}`;
674→    }
675→
676→    if(hours > 0){
677→        return `${hours} hour${hours === 1 ? "" : "s"}, ${minutes} min${minutes === 1 ? "" : "s"}`;
678→    }
679→
680→    return `${minutes} min${minutes === 1 ? "" : "s"}`;
681→};
