683→const isCanvasBackgroundTarget = (target, stage) => {
684→    if(!target || !stage){
685→        return false;
686→    }
687→
688→    if(target === stage){
689→        return true;
690→    }
691→
692→    return target.getParent?.() === stage;
693→};
